def _transform(name: str, spec: str, known: dict[str, str]) -> str:
    """Evaluate ONE identifier transform from its YAML spec. A DECLARED VOCABULARY, deliberately tiny.

        strip_prefix:PMC                              PMC12754963 -> 12754963
        format:oai:pubmedcentral.nih.gov:{pmcid_numeric}

    Adding a repository whose OAI identifier is shaped differently is a ROW, not a function. An unknown
    verb RAISES — it does not silently yield '' and become a URL with a hole in it.
    """
    verb, _, arg = spec.partition(':')
    if verb == 'strip_prefix':
        v = known.get(name.replace('_numeric', ''), '') or ''
        # the source id for `pmcid_numeric` is `pmcid`; resolve it generically from what we already know
        if not v:
            for k, val in known.items():
                if name.startswith(k):
                    v = val
                    break
        return v[len(arg):] if v.upper().startswith(arg.upper()) else v
    if verb == 'format':
        try:
            return arg.format(**known)
        except KeyError as e:
            raise KeyError(f'transform {name!r} needs identifier {e} which we have not derived yet')
    raise ValueError(f'unknown identifier transform verb {verb!r} in {spec!r} — it is not in the '
                     f'declared vocabulary (strip_prefix | format)')

